PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasReal_Estate_Agencies ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Real_Estate_Agencies } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?description WHERE {
  ?real_estate_agencies_services a :Real_Estate_Agencies_Services .
  ?services a :Services .
  ?real_estate_agencies_services p:hasServices ?services .
  ?real_estate_agencies a :Real_Estate_Agencies .
